import json
import re

# Load data
pa_papers = json.load(open(locals()['var_functions.query_db:34'], 'r'))
citations = json.load(open(locals()['var_functions.query_db:4'], 'r'))

citation_map = {record['title']: int(record['total_citations']) for record in citations}

def extract_year(text):
    text_start = text[:5000]
    if '2016' in text_start:
        return 2016
    conferences = ['CHI', 'UbiComp', 'CSCW', 'DIS', 'PervasiveHealth', 'WWW', 'IUI', 'OzCHI', 'TEI', 'AH']
    for conf in conferences:
        pattern = conf + r"\\s*['\"']?\\s*16\\b"
        if re.search(pattern, text_start, re.IGNORECASE):
            return 2016
    return None

papers_2016 = []
for paper in pa_papers:
    if extract_year(paper['text']) == 2016:
        title = paper['filename'].replace('.txt', '')
        papers_2016.append({'title': title, 'year': 2016, 'total_citations': citation_map.get(title, 0)})

papers_2016.sort(key=lambda x: x['total_citations'], reverse=True)
print("Found", len(papers_2016), "papers")
for p in papers_2016[:10]:
    print(p['title'], ":", p['total_citations'], "citations")

result = json.dumps(papers_2016)
print('__RESULT__:')
print(result)
"}

